// CONVENIENCE
// ═══════════════════════════════════════════════════════════════════════════

/** All 1062 supported ticker symbols */
export const ALL_TICKERS: string[] = Object.keys(PYTH_ACCOUNTS).sort()

/** Resolve ticker → asset class info (leverage, fees) */
export function getAssetClass(ticker: string): AssetClassInfo {
  for (const [cat, tickers] of Object.entries(TICKER_CATEGORIES)) {
    if (tickers.includes(ticker)) {
      const ac = CATEGORY_ASSET_CLASS[cat]
      if (ac && ASSET_CLASSES[ac]) return ASSET_CLASSES[ac]
    }
  }
  return ASSET_CLASSES['Crypto'] // default, matches etc.rs
}

/** Fetch price from Pyth Hermes (browser-safe, no API key) */
export async function fetchTickerPrice(ticker: string): Promise<number | null> {
  const hex = PYTH_HEX[ticker]
  if (!hex) return null
  try {
    const r = await fetch(`https://hermes.pyth.network/api/latest_price_feeds?ids[]=${hex}`)
    if (!r.ok) return null
    const json = await r.json()
    const p = json?.[0]?.price
    if (!p) return null
    return Number(p.price) * Math.pow(10, p.expo)
  } catch { return null }
}

/** Batch-fetch prices from Pyth Hermes */
export async function fetchBatchPrices(tickers: string[]): Promise<Record<string, number>> {
  const ids = tickers.map(t => PYTH_HEX[t]).filter(Boolean)
  if (!ids.length) return {}
  try {
    const qs = ids.map(h => `ids[]=${h}`).join('&')
    const r = await fetch(`https://hermes.pyth.network/api/latest_price_feeds?${qs}`)
    if (!r.ok) return {}
    const out: Record<string, number> = {}
    for (const feed of await r.json()) {
      const hexId = '0x' + feed.id
      const t = Object.entries(PYTH_HEX).find(([, v]) => v === hexId)?.[0]
      if (t && feed.price) out[t] = Number(feed.price.price) * Math.pow(10, feed.price.expo)
    }
    return out
  } catch { return {} }
}
